scripts.script:
import java.util.zip.*
import java.nio.file.*

def buildDir = new File(project.build.directory)
def stamp    = new File(buildDir, 'repack.stamp')
def outJar   = new File(buildDir, project.build.finalName + '.jar')
def kcompJar = new File(project.properties['org.jetbrains.kotlin:kotlin-compiler:jar'])

// Fast no-clean guard.
if (stamp.exists() && outJar.exists() &&
    stamp.lastModified() >= kcompJar.lastModified()) {
  log.info('KotlinCompilerCliBase: up-to-date, skipping extraction.')
  return
}

// Build entry sets for set-difference.
def collectEntriesFromFile = { File f ->
  if (!f?.exists()) return [] as Set
  def s = new HashSet<String>()
  new ZipFile(f).withCloseable { zf -> zf.entries().each { s.add(it.name) } }
  s
}

// Classes already in -for-ide artifacts (don't override them).
def forIdeEntries = new HashSet<String>()
def platformEntries = new HashSet<String>()
project.artifacts.each { art ->
  if (art.scope != 'provided') return
  def file = art.file
  if (!file?.exists()) return
  def key = "${art.groupId}:${art.artifactId}"
  if (key == 'org.jetbrains.kotlin:kotlin-compiler-common-for-ide' ||
      key == 'org.jetbrains.kotlin:kotlin-compiler-ir-for-ide') {
    forIdeEntries.addAll(collectEntriesFromFile(file))
  } else if (key != 'org.jetbrains.kotlin:kotlin-compiler') {
    // All other provided deps are platform JARs — collect them for exclusion
    platformEntries.addAll(collectEntriesFromFile(file))
  }
}

log.info("KotlinCompilerCliBase: forIde=${forIdeEntries.size()}, platform=${platformEntries.size()}")

// Extract from kotlin-compiler.jar every .class that is not already provided by:
//   - kotlin-compiler-common-for-ide or kotlin-compiler-ir-for-ide (forIdeEntries)
//   - platform 242 JARs (platformEntries)
// This captures cli/**, com/intellij/**, third-party shaded deps (aalto, stax2, etc.)
// and any other Kotlin runtime classes absent from the -for-ide thin artifacts.
def classesDir = new File(buildDir, 'classes')
classesDir.deleteDir()
classesDir.mkdirs()

// Classes where the fat jar's newer Kotlin version must override the platform's Java version.
// The platform JAR contains an older Java Registry; analysis-api 2.3.21 requires the Kotlin
// version (with Registry$Companion) from the fat jar.
def forceInclude = [
  'com/intellij/openapi/util/registry/Registry.class',
  'com/intellij/openapi/util/registry/Registry$1.class',
  'com/intellij/openapi/util/registry/Registry$2.class',
] as Set

int extracted = 0
new ZipFile(kcompJar).withCloseable { zf ->
  zf.entries().each { e ->
    def name = e.name
    if (!name.endsWith('.class')) return
    boolean keep = forceInclude.contains(name) ||
                   (!forIdeEntries.contains(name) && !platformEntries.contains(name))
    if (!keep) return

    def target = new File(classesDir, name)
    target.parentFile.mkdirs()
    target.bytes = zf.getInputStream(e).bytes
    extracted++
  }
}
log.info("KotlinCompilerCliBase: extracted $extracted classes")

// Build the output JAR.
def zos = new ZipOutputStream(new FileOutputStream(outJar))
classesDir.eachFileRecurse { f ->
  if (!f.isFile()) return
  def rel = classesDir.toURI().relativize(f.toURI()).toString()
  zos.putNextEntry(new ZipEntry(rel))
  zos.write(f.bytes)
  zos.closeEntry()
}
zos.close()

stamp.text = new Date().toString()
log.info("KotlinCompilerCliBase: wrote ${outJar.length()} bytes to ${outJar.name}")
